Here's how to handle each scenario with modern MSTest (3.9+/3.10+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class EnvironmentSpecificTests
{
    private readonly TestContext _testContext;
    private string? _tempFilePath;

    public EnvironmentSpecificTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skip on other OSes
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void WindowsRegistry_ReadsInstallPath()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\MyApp", "InstallPath", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI: runs only locally
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    [Timeout(30000)]
    public async Task GpuRendering_ProducesExpectedOutput()
    {
        var result = await GpuRenderer.RenderAsync(_testContext.CancellationToken);
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API: retry up to 3 times
    [TestMethod]
    [Retry(3)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync("Seattle");
        Assert.IsNotNull(forecast);
        Assert.IsNotEmpty(forecast.Days);
    }

    // 4. Temp files: TestCleanup runs even if the test fails
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFilePath = Path.Combine(Path.GetTempPath(), $"{Guid.NewGuid()}.csv");

        Exporter.WriteCsv(_tempFilePath, new[] { "a", "b" });

        Assert.IsTrue(File.Exists(_tempFilePath));
        Assert.StartsWith("a,b", File.ReadAllText(_tempFilePath));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFilePath is not null && File.Exists(_tempFilePath))
        {
            File.Delete(_tempFilePath);
        }
    }
}
```

**Summary of the four patterns:**

| Scenario | Solution | MSTest version |
|---|---|---|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky external API | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | All versions |

**Key notes:**
- `[OSCondition]` and `[CICondition]` **skip** (not fail) when the condition isn't met.
- `[Retry]` should only be used for genuinely flaky external dependencies — not to mask race conditions or shared-state bugs.
- `[TestCleanup]` always runs after each test, even on failure or exception, making it the right place for file/resource cleanup.
- Pair `[Timeout]` with `TestContext.CancellationToken` for async tests to ensure proper cooperative cancellation.
